#!/usr/bin/env python3
# apply_ios.py - School v4 iOS Design Installer
import base64, os, shutil, datetime

print("=" * 55)
print("  School v4 - iOS Design Installer")
print("=" * 55)

# Backup
for f in ["styles.css","index.html","app.js"]:
    if os.path.exists(f):
        shutil.copy2(f, f+".bak_"+datetime.datetime.now().strftime("%H%M%S"))
        print("  Backup:", f)

# 1. styles.css
css=base64.b64decode("").decode("utf-8")
open("styles.css","w",encoding="utf-8").write(css)
print("[OK] styles.css:", len(css), "bytes")

# 2. index.html
html=base64.b64decode("").decode("utf-8")
open("index.html","w",encoding="utf-8").write(html)
print("[OK] index.html:", len(html), "bytes")

# 3. Fix app.js
fix=base64.b64decode("").decode("utf-8")
exec(fix)

print()
print("=" * 55)
print("  LISTO! Diseno iOS aplicado")
print("=" * 55)
print("Ejecuta:")
print("  kill $(lsof -t -i:8080) 2>/dev/null; sleep 1")
print("  python3 -m http.server 8080 & sleep 1 && xdg-open http://localhost:8080")
